/**
 * Get the plural categories required by a locale.
 *
 * Lookup order:
 * 1. Exact match on the full locale code (e.g., "pt-PT" or "pt_PT")
 * 2. Normalized separator match (CLDR uses hyphens, GameScript uses underscores)
 * 3. Language subtag only (e.g., "pt")
 * 4. Default: ["other"]
 */
export function getRequiredPluralCategories(localeCode: string): readonly PluralCategory[] {
  // Exact match
  const exact = PLURAL_RULES.get(localeCode);
  if (exact) return exact;

  // Normalize separator: CLDR keys use hyphens, GameScript locale names use underscores
  const normalized = localeCode.includes('_') ? localeCode.replace(/_/g, '-') : localeCode.replace(/-/g, '_');
  const normalizedMatch = PLURAL_RULES.get(normalized);
  if (normalizedMatch) return normalizedMatch;

  // Language subtag fallback (split on - or _)
  const lang = localeCode.split(/[-_]/)[0];
  if (lang !== localeCode) {
    const langMatch = PLURAL_RULES.get(lang);
    if (langMatch) return langMatch;
  }

  return DEFAULT_CATEGORIES;
}

/**
 * Check if a locale code is known to CLDR (has plural rules).
 * Uses the same normalization as getRequiredPluralCategories.
 */
export function isKnownLocale(localeCode: string): boolean {
  if (PLURAL_RULES.has(localeCode)) return true;
  const normalized = localeCode.includes('_') ? localeCode.replace(/_/g, '-') : localeCode.replace(/-/g, '_');
  if (PLURAL_RULES.has(normalized)) return true;
  const lang = localeCode.split(/[-_]/)[0];
  if (lang !== localeCode && PLURAL_RULES.has(lang)) return true;
  return false;
}
